create extension if not exists "pgcrypto";
create table if not exists public.profiles (id uuid primary key default gen_random_uuid(), username text unique not null, display_name text, avatar_url text, role text default 'Лаборант', rank_title text default 'Лаборант', mutation_score int default 0, is_admin boolean default false, created_at timestamptz default now());
create table if not exists public.projects (id uuid primary key default gen_random_uuid(), owner_id uuid references public.profiles(id) on delete set null, title text not null, subtitle text, description text not null, category text not null default 'visual', status text not null default 'raw', phase text default 'Фаза 01: Сырой образец', mutation_level int default 10, missing_items text[] default '{}', tags text[] default '{}', cover_url text, is_collective boolean default false, is_archived boolean default false, needs_help boolean default true, is_experiment_of_day boolean default false, created_at timestamptz default now(), updated_at timestamptz default now());
create table if not exists public.project_files (id uuid primary key default gen_random_uuid(), project_id uuid references public.projects(id) on delete cascade, name text not null, file_url text not null, file_type text, file_size bigint, purpose text default 'source', created_at timestamptz default now());
create table if not exists public.reagents (id uuid primary key default gen_random_uuid(), project_id uuid references public.projects(id) on delete cascade, author_id uuid references public.profiles(id) on delete set null, title text not null, body text not null, reagent_type text not null default 'addition', intervention_type text default 'Дополнение', impact_score int default 10, branch_name text default 'Основная ветка', acceptance_status text default 'candidate', result_url text, created_at timestamptz default now());
create table if not exists public.reagent_files (id uuid primary key default gen_random_uuid(), reagent_id uuid references public.reagents(id) on delete cascade, name text not null, file_url text not null, file_type text, file_size bigint, created_at timestamptz default now());
create table if not exists public.observations (id uuid primary key default gen_random_uuid(), project_id uuid references public.projects(id) on delete cascade, author_id uuid references public.profiles(id) on delete set null, body text not null, created_at timestamptz default now());
create table if not exists public.project_versions (id uuid primary key default gen_random_uuid(), project_id uuid references public.projects(id) on delete cascade, author_id uuid references public.profiles(id) on delete set null, version_label text not null, phase text not null, description text, created_at timestamptz default now());
create table if not exists public.mutation_history (id uuid primary key default gen_random_uuid(), project_id uuid references public.projects(id) on delete cascade, actor_id uuid references public.profiles(id) on delete set null, event_text text not null, created_at timestamptz default now());
create table if not exists public.activity_feed (id uuid primary key default gen_random_uuid(), actor_id uuid references public.profiles(id) on delete set null, project_id uuid references public.projects(id) on delete cascade, text text not null, href text, created_at timestamptz default now());
create table if not exists public.journal_posts (id uuid primary key default gen_random_uuid(), title text not null, slug text unique not null, category text default 'Истории', excerpt text, body text, read_time int default 5, created_at timestamptz default now());
